#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5,M=1e6+10;

int n,m;
int head[N],ver[M],nxt[M],tot;
int dfn[N],low[N],siz[N],num;
long long ans[N];

void add(int u,int v){
    ver[++tot]=v,nxt[tot]=head[u],head[u]=tot;
}

void tarjan(int x){
    siz[x]=1;
    dfn[x]=low[x]=++num;
    int sum=0;
    for(int i=head[x],y;i;i=nxt[i])
        if(!dfn[y=ver[i]]){
            tarjan(y);
            siz[x]+=siz[y];
            low[x]=min(low[x],low[y]);
            if(low[y]>=dfn[x]){
                ans[x]+=1LL*sum*siz[y];
                sum+=siz[y];
            }
        }else
            low[x]=min(low[x],dfn[y]);
    ans[x]+=1LL*sum*(n-sum-1);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=0,u,v;i<m;i++){
        scanf("%d%d",&u,&v);
        add(u,v);
        add(v,u);
    }
    tarjan(1);
    for(int i=1;i<=n;i++)
        printf("%lld\n",ans[i]*2+2*(n-1));
    return 0;
}
